"""
Skept Prototype — Backend API
Frontend HTML is embedded directly to avoid Docker path issues.
"""

import asyncio
import os
import uuid
import tempfile
import shutil
from contextlib import asynccontextmanager
from pathlib import Path

from fastapi import FastAPI, UploadFile, File, Form, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from fastapi.responses import JSONResponse, HTMLResponse
import aiofiles

from analysers.metadata import run_metadata
from analysers.deepfake import run_deepfake
from analysers.fusion import fuse
from analysers.source_reputation import run_reputation
from analysers.c2pa import run_c2pa

jobs: dict[str, dict] = {}

@asynccontextmanager
async def lifespan(app: FastAPI):
    yield
    for job in jobs.values():
        wd = job.get("workdir")
        if wd and Path(wd).exists():
            shutil.rmtree(wd, ignore_errors=True)

app = FastAPI(title="Skept API", version="0.1.0", lifespan=lifespan)

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_methods=["*"],
    allow_headers=["*"],
)

FRONTEND_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8">\n  <meta name="viewport" content="width=device-width, initial-scale=1.0">\n  <title>Skept — Prototype</title>\n  <link rel="preconnect" href="https://fonts.googleapis.com">\n  <link href="https://fonts.googleapis.com/css2?family=EB+Garamond:ital,wght@0,400;0,500;1,400;1,500&family=Inter:wght@300;400;500;600&display=swap" rel="stylesheet">\n  <style>\n    :root {\n      --amber:       #DFB87B;\n      --amber-light: #F5E6C8;\n      --amber-pale:  #FAF5EC;\n      --ink:         #1A1A1A;\n      --gray:        #4A4A4A;\n      --soft:        #8A8A8A;\n      --rule:        #E0E0E0;\n      --cream:       #FAF8F5;\n      --green:       #2D7A4F;\n      --green-bg:    #EBF5EF;\n      --red:         #C0392B;\n      --red-bg:      #FDECEA;\n      --amber-bg:    #FEF9EE;\n    }\n\n    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n    body {\n      font-family: \'Inter\', sans-serif;\n      background: var(--cream);\n      color: var(--ink);\n      min-height: 100vh;\n    }\n\n    /* ── Nav ───────────────────────────────────────────────────────────────── */\n    nav {\n      position: sticky; top: 0; z-index: 100;\n      background: rgba(250,248,245,0.92);\n      backdrop-filter: blur(12px);\n      border-bottom: 1px solid var(--rule);\n      padding: 0 32px;\n      height: 56px;\n      display: flex; align-items: center; justify-content: space-between;\n    }\n    .nav-brand {\n      display: flex; align-items: center; gap: 10px;\n      font-family: \'EB Garamond\', serif;\n      font-style: italic; font-size: 22px;\n      color: var(--ink); text-decoration: none;\n    }\n    .nav-loupe {\n      width: 28px; height: 28px;\n      border: 2px solid var(--ink);\n      border-radius: 50%;\n      position: relative;\n    }\n    .nav-loupe::after {\n      content: \'\';\n      position: absolute; bottom: -7px; right: -7px;\n      width: 10px; height: 2px;\n      background: var(--ink);\n      transform: rotate(45deg);\n      transform-origin: left center;\n    }\n    .nav-badge {\n      font-family: \'Inter\', sans-serif;\n      font-size: 10px; font-weight: 600;\n      letter-spacing: 0.12em; text-transform: uppercase;\n      color: var(--amber); font-style: normal;\n      border: 1px solid var(--amber);\n      padding: 2px 7px; border-radius: 3px;\n    }\n\n    /* ── Main layout ────────────────────────────────────────────────────────── */\n    main {\n      max-width: 720px;\n      margin: 0 auto;\n      padding: 64px 24px 120px;\n    }\n\n    /* ── Intake ─────────────────────────────────────────────────────────────── */\n    #view-intake { display: block; }\n    #view-analysing { display: none; }\n    #view-verdict { display: none; }\n\n    .intake-eyebrow {\n      font-size: 11px; font-weight: 600;\n      letter-spacing: 0.18em; text-transform: uppercase;\n      color: var(--amber); margin-bottom: 24px;\n      display: flex; align-items: center; gap: 10px;\n    }\n    .intake-eyebrow::after {\n      content: \'\'; flex: 0 0 28px; height: 1px;\n      background: var(--amber); opacity: 0.4;\n    }\n\n    h1 {\n      font-family: \'EB Garamond\', serif;\n      font-size: clamp(36px, 5vw, 52px);\n      font-weight: 400; line-height: 1.1;\n      letter-spacing: -0.02em;\n      margin-bottom: 16px;\n    }\n    h1 em { font-style: italic; color: var(--amber); }\n\n    .intake-lead {\n      font-size: 17px; color: var(--gray);\n      line-height: 1.65; font-weight: 300;\n      margin-bottom: 48px; max-width: 520px;\n    }\n\n    /* Tab bar */\n    .input-tabs {\n      display: flex; gap: 0;\n      border-bottom: 1px solid var(--rule);\n      margin-bottom: 28px;\n    }\n    .tab-btn {\n      padding: 10px 20px;\n      font-size: 13px; font-weight: 500;\n      color: var(--soft); background: none;\n      border: none; border-bottom: 2px solid transparent;\n      cursor: pointer; transition: all 0.15s;\n      margin-bottom: -1px;\n    }\n    .tab-btn.active {\n      color: var(--ink);\n      border-bottom-color: var(--amber);\n    }\n    .tab-btn:hover:not(.active) { color: var(--gray); }\n\n    /* URL input */\n    #tab-url, #tab-file { display: none; }\n    #tab-url.active-tab, #tab-file.active-tab { display: block; }\n\n    .url-row {\n      display: flex; gap: 10px;\n    }\n    .url-input {\n      flex: 1;\n      padding: 13px 16px;\n      border: 1.5px solid var(--rule);\n      border-radius: 6px;\n      font-family: \'Inter\', sans-serif;\n      font-size: 14px; color: var(--ink);\n      background: white;\n      transition: border-color 0.15s;\n      outline: none;\n    }\n    .url-input:focus { border-color: var(--amber); }\n    .url-input::placeholder { color: var(--soft); }\n\n    .analyse-btn {\n      padding: 13px 28px;\n      background: var(--ink); color: white;\n      border: none; border-radius: 6px;\n      font-family: \'Inter\', sans-serif;\n      font-size: 14px; font-weight: 500;\n      cursor: pointer; white-space: nowrap;\n      transition: opacity 0.15s;\n    }\n    .analyse-btn:hover { opacity: 0.85; }\n    .analyse-btn:disabled { opacity: 0.4; cursor: not-allowed; }\n\n    /* File drop zone */\n    .dropzone {\n      border: 2px dashed var(--rule);\n      border-radius: 8px;\n      padding: 48px 32px;\n      text-align: center;\n      cursor: pointer;\n      transition: border-color 0.15s, background 0.15s;\n      background: white;\n    }\n    .dropzone:hover, .dropzone.drag-over {\n      border-color: var(--amber);\n      background: var(--amber-pale);\n    }\n    .dropzone input { display: none; }\n    .dropzone-icon {\n      font-size: 32px; margin-bottom: 12px;\n    }\n    .dropzone-label {\n      font-size: 14px; color: var(--gray);\n    }\n    .dropzone-label strong { color: var(--ink); }\n    .dropzone-meta {\n      font-size: 12px; color: var(--soft); margin-top: 6px;\n    }\n    .file-selected {\n      display: flex; align-items: center;\n      gap: 12px; margin-top: 16px;\n      padding: 12px 16px;\n      background: var(--amber-light);\n      border-radius: 6px;\n      font-size: 13px;\n    }\n    .file-selected span { flex: 1; font-weight: 500; }\n\n    /* Platform hints */\n    .platform-chips {\n      display: flex; flex-wrap: wrap; gap: 8px;\n      margin-top: 20px;\n    }\n    .chip {\n      font-size: 11px; font-weight: 500;\n      color: var(--soft);\n      border: 1px solid var(--rule);\n      padding: 4px 10px; border-radius: 20px;\n    }\n\n    /* ── Analysing view ─────────────────────────────────────────────────────── */\n    .analysing-header {\n      margin-bottom: 40px;\n    }\n    .analysing-label {\n      font-family: \'EB Garamond\', serif;\n      font-size: 32px; font-weight: 400;\n      margin-bottom: 8px;\n    }\n    .analysing-sub {\n      font-size: 14px; color: var(--soft);\n    }\n\n    .stage-label {\n      font-size: 10px; font-weight: 600;\n      letter-spacing: 0.14em; text-transform: uppercase;\n      color: var(--soft); margin-bottom: 12px;\n    }\n\n    .signal-list { display: flex; flex-direction: column; gap: 10px; }\n\n    .signal-row {\n      display: flex; align-items: center; gap: 14px;\n      padding: 14px 18px;\n      background: white;\n      border: 1px solid var(--rule);\n      border-radius: 8px;\n      transition: all 0.3s;\n    }\n    .signal-row.running {\n      border-color: var(--amber);\n      background: var(--amber-pale);\n    }\n    .signal-row.complete { opacity: 1; }\n    .signal-row.pending { opacity: 0.45; }\n\n    .signal-icon {\n      width: 32px; height: 32px; border-radius: 50%;\n      display: flex; align-items: center; justify-content: center;\n      flex-shrink: 0; font-size: 14px;\n      background: var(--rule); color: var(--soft);\n      transition: all 0.3s;\n    }\n    .signal-row.running .signal-icon {\n      background: var(--amber); color: white;\n      animation: pulse-icon 1.4s ease-in-out infinite;\n    }\n    .signal-row.complete .signal-icon {\n      background: var(--green-bg); color: var(--green);\n    }\n    @keyframes pulse-icon {\n      0%, 100% { transform: scale(1); opacity: 1; }\n      50% { transform: scale(1.1); opacity: 0.8; }\n    }\n\n    .signal-name {\n      flex: 1; font-size: 14px; font-weight: 500;\n    }\n    .signal-status {\n      font-size: 12px; color: var(--soft);\n    }\n    .signal-row.running .signal-status { color: var(--amber); }\n    .signal-row.complete .signal-status { color: var(--green); }\n\n    .progress-bar {\n      margin-top: 32px;\n      height: 3px; background: var(--rule);\n      border-radius: 2px; overflow: hidden;\n    }\n    .progress-fill {\n      height: 100%; background: var(--amber);\n      border-radius: 2px;\n      transition: width 0.4s ease;\n      width: 0%;\n    }\n\n    /* ── Verdict view ────────────────────────────────────────────────────────── */\n    .verdict-band {\n      padding: 28px 32px;\n      border-radius: 12px;\n      margin-bottom: 32px;\n      display: flex; align-items: center; gap: 20px;\n    }\n    .verdict-band.green {\n      background: var(--green-bg);\n      border: 1.5px solid #2D7A4F40;\n    }\n    .verdict-band.amber {\n      background: var(--amber-bg);\n      border: 1.5px solid #DFB87B60;\n    }\n    .verdict-band.red {\n      background: var(--red-bg);\n      border: 1.5px solid #C0392B40;\n    }\n\n    .verdict-indicator {\n      width: 48px; height: 48px;\n      border-radius: 50%;\n      flex-shrink: 0;\n      display: flex; align-items: center; justify-content: center;\n      font-size: 22px;\n    }\n    .green .verdict-indicator { background: var(--green); }\n    .amber .verdict-indicator { background: var(--amber); }\n    .red .verdict-indicator { background: var(--red); }\n\n    .verdict-text h2 {\n      font-family: \'EB Garamond\', serif;\n      font-size: 24px; font-weight: 500;\n      margin-bottom: 4px;\n    }\n    .green .verdict-text h2 { color: var(--green); }\n    .amber .verdict-text h2 { color: #8B6914; }\n    .red .verdict-text h2 { color: var(--red); }\n\n    .verdict-text p {\n      font-size: 13px; line-height: 1.6;\n      color: var(--gray);\n    }\n\n    .score-bar-wrap {\n      margin-bottom: 32px;\n    }\n    .score-bar-label {\n      display: flex; justify-content: space-between;\n      font-size: 11px; color: var(--soft);\n      margin-bottom: 8px;\n    }\n    .score-bar {\n      height: 6px; background: var(--rule);\n      border-radius: 3px; overflow: hidden;\n      position: relative;\n    }\n    .score-fill {\n      height: 100%; border-radius: 3px;\n      transition: width 0.6s ease;\n    }\n    .score-fill.green { background: var(--green); }\n    .score-fill.amber { background: var(--amber); }\n    .score-fill.red { background: var(--red); }\n\n    /* Evidence cards */\n    .evidence-section {\n      margin-bottom: 28px;\n    }\n    .evidence-section h3 {\n      font-size: 11px; font-weight: 600;\n      letter-spacing: 0.12em; text-transform: uppercase;\n      color: var(--soft); margin-bottom: 12px;\n      padding-bottom: 8px;\n      border-bottom: 1px solid var(--rule);\n    }\n\n    .evidence-card {\n      background: white;\n      border: 1px solid var(--rule);\n      border-radius: 8px;\n      overflow: hidden;\n      margin-bottom: 10px;\n    }\n    .evidence-card-header {\n      display: flex; align-items: center;\n      gap: 12px; padding: 14px 18px;\n      cursor: pointer;\n    }\n    .evidence-card-header:hover { background: var(--cream); }\n    .evidence-card-title {\n      flex: 1; font-size: 14px; font-weight: 500;\n    }\n    .evidence-card-score {\n      font-size: 13px; font-weight: 600;\n    }\n    .evidence-card-score.green { color: var(--green); }\n    .evidence-card-score.amber { color: #8B6914; }\n    .evidence-card-score.red { color: var(--red); }\n\n    .evidence-card-body {\n      padding: 0 18px 18px;\n      border-top: 1px solid var(--rule);\n      display: none;\n    }\n    .evidence-card-body.open { display: block; }\n\n    .evidence-summary {\n      font-size: 13px; line-height: 1.7;\n      color: var(--gray); padding: 14px 0 10px;\n    }\n\n    .signal-table { width: 100%; border-collapse: collapse; margin-top: 8px; }\n    .signal-table td {\n      padding: 7px 0; font-size: 13px;\n      border-bottom: 1px solid var(--rule);\n      vertical-align: top;\n    }\n    .signal-table tr:last-child td { border-bottom: none; }\n    .signal-table .sig-label { color: var(--gray); width: 55%; }\n    .signal-table .sig-value { font-weight: 500; text-align: right; }\n    .sig-flag { color: var(--red); font-size: 11px; }\n\n    /* Disclaimer */\n    .disclaimer {\n      padding: 14px 18px;\n      background: var(--amber-pale);\n      border: 1px solid var(--amber-light);\n      border-radius: 6px;\n      font-size: 12px; line-height: 1.6;\n      color: var(--gray); margin-bottom: 24px;\n    }\n\n    .retry-btn {\n      display: inline-flex; align-items: center; gap: 8px;\n      padding: 12px 24px;\n      border: 1.5px solid var(--ink);\n      border-radius: 6px;\n      font-family: \'Inter\', sans-serif;\n      font-size: 13px; font-weight: 500;\n      color: var(--ink); background: none;\n      cursor: pointer; text-decoration: none;\n      transition: all 0.15s;\n    }\n    .retry-btn:hover { background: var(--ink); color: white; }\n\n    /* Error */\n    .error-box {\n      padding: 20px 24px;\n      background: var(--red-bg);\n      border: 1px solid #C0392B30;\n      border-radius: 8px;\n      margin-top: 16px;\n      font-size: 14px; color: var(--red);\n    }\n  </style>\n</head>\n<body>\n\n<nav>\n  <a class="nav-brand" href="#">\n    <div class="nav-loupe"></div>\n    Skept\n  </a>\n  <span class="nav-badge">Prototype v0.1</span>\n</nav>\n\n<main>\n\n  <!-- ═══════════════════════════════════════════\n       VIEW 1: INTAKE\n       ═══════════════════════════════════════════ -->\n  <div id="view-intake">\n    <div class="intake-eyebrow">A second look, before the share</div>\n    <h1><em>Look closer</em><br>at every clip.</h1>\n    <p class="intake-lead">\n      Paste a link or upload a video. Skept analyses metadata,\n      container forensics, and frame-level signals to return an\n      evidence-backed verdict.\n    </p>\n\n    <div class="input-tabs">\n      <button class="tab-btn active" onclick="switchTab(\'url\')">Paste URL</button>\n      <button class="tab-btn" onclick="switchTab(\'file\')">Upload file</button>\n    </div>\n\n    <div id="tab-url" class="active-tab">\n      <div class="url-row">\n        <input\n          class="url-input"\n          id="url-input"\n          type="url"\n          placeholder="https://www.tiktok.com/@… or YouTube, Instagram, X…"\n          autocomplete="off"\n        >\n        <button class="analyse-btn" id="url-btn" onclick="submitUrl()">Analyse</button>\n      </div>\n    </div>\n\n    <div id="tab-file">\n      <div class="dropzone" id="dropzone" onclick="document.getElementById(\'file-input\').click()">\n        <input type="file" id="file-input" accept="video/*" onchange="fileSelected(this)">\n        <div class="dropzone-icon">🎬</div>\n        <div class="dropzone-label">\n          <strong>Drop a video file here</strong> or click to browse\n        </div>\n        <div class="dropzone-meta">MP4, MOV, WebM · up to 500 MB</div>\n      </div>\n      <div id="file-info" style="display:none">\n        <div class="file-selected">\n          <span>📄</span>\n          <span id="file-name"></span>\n          <button class="analyse-btn" id="file-btn" onclick="submitFile()">Analyse</button>\n        </div>\n      </div>\n    </div>\n\n    <div class="platform-chips">\n      <span class="chip">TikTok</span>\n      <span class="chip">Instagram</span>\n      <span class="chip">YouTube Shorts</span>\n      <span class="chip">X / Twitter</span>\n      <span class="chip">Bluesky</span>\n      <span class="chip">Facebook</span>\n      <span class="chip">Discord CDN</span>\n      <span class="chip">Direct file</span>\n    </div>\n\n    <div id="intake-error" class="error-box" style="display:none"></div>\n  </div>\n\n\n  <!-- ═══════════════════════════════════════════\n       VIEW 2: ANALYSING\n       ═══════════════════════════════════════════ -->\n  <div id="view-analysing">\n    <div class="analysing-header">\n      <div class="analysing-label">Analysing clip…</div>\n      <div class="analysing-sub" id="analysing-input"></div>\n    </div>\n\n    <div class="stage-label">Stage 1 — Cheap signals (no GPU)</div>\n    <div class="signal-list">\n      <div class="signal-row pending" id="sig-ingest">\n        <div class="signal-icon">⬇</div>\n        <div class="signal-name">Ingestion &amp; normalisation</div>\n        <div class="signal-status">Waiting…</div>\n      </div>\n      <div class="signal-row pending" id="sig-metadata">\n        <div class="signal-icon">🗂</div>\n        <div class="signal-name">Metadata &amp; container forensics</div>\n        <div class="signal-status">Waiting…</div>\n      </div>\n      <div class="signal-row pending" id="sig-reputation">\n        <div class="signal-icon">👤</div>\n        <div class="signal-name">Source reputation</div>\n        <div class="signal-status">Waiting…</div>\n      </div>\n      <div class="signal-row pending" id="sig-c2pa">\n        <div class="signal-icon">🔏</div>\n        <div class="signal-name">C2PA provenance</div>\n        <div class="signal-status">Waiting…</div>\n      </div>\n    </div>\n\n    <br>\n    <div class="stage-label" style="margin-top:20px">Stage 2 — GPU ensemble</div>\n    <div class="signal-list">\n      <div class="signal-row pending" id="sig-deepfake">\n        <div class="signal-icon">🧠</div>\n        <div class="signal-name">Frame-level deepfake detection</div>\n        <div class="signal-status">Waiting for Stage 1…</div>\n      </div>\n    </div>\n\n    <div class="progress-bar" style="margin-top:32px">\n      <div class="progress-fill" id="progress-fill"></div>\n    </div>\n  </div>\n\n\n  <!-- ═══════════════════════════════════════════\n       VIEW 3: VERDICT\n       ═══════════════════════════════════════════ -->\n  <div id="view-verdict">\n\n    <div id="verdict-band" class="verdict-band amber">\n      <div class="verdict-indicator">◑</div>\n      <div class="verdict-text">\n        <h2 id="verdict-label">Inconclusive</h2>\n        <p id="verdict-desc"></p>\n      </div>\n    </div>\n\n    <div class="score-bar-wrap">\n      <div class="score-bar-label">\n        <span>Authentic</span>\n        <span id="score-pct"></span>\n        <span>Manipulated</span>\n      </div>\n      <div class="score-bar">\n        <div class="score-fill amber" id="score-fill"></div>\n      </div>\n    </div>\n\n    <div id="evidence-cards"></div>\n\n    <div id="verdict-disclaimer" class="disclaimer"></div>\n\n    <button class="retry-btn" onclick="reset()">← Analyse another clip</button>\n  </div>\n\n</main>\n\n<script>\n  /* ══════════════════════════════════════════════════════════\n     CONFIG — update API_BASE if running on a different port\n     ══════════════════════════════════════════════════════════ */\n  const API_BASE = window.SKEPT_API || (window.location.hostname === \'localhost\' ? \'http://localhost:8000\' : window.location.origin);\n\n  /* ── Tab switching ──────────────────────────────────────── */\n  function switchTab(name) {\n    document.querySelectorAll(\'.tab-btn\').forEach((b, i) => {\n      b.classList.toggle(\'active\', (name === \'url\' && i === 0) || (name === \'file\' && i === 1));\n    });\n    document.getElementById(\'tab-url\').classList.toggle(\'active-tab\', name === \'url\');\n    document.getElementById(\'tab-file\').classList.toggle(\'active-tab\', name === \'file\');\n  }\n\n  /* ── File selection ─────────────────────────────────────── */\n  let selectedFile = null;\n\n  function fileSelected(input) {\n    selectedFile = input.files[0];\n    if (!selectedFile) return;\n    document.getElementById(\'file-name\').textContent = selectedFile.name;\n    document.getElementById(\'file-info\').style.display = \'block\';\n  }\n\n  // Drag-and-drop\n  const dz = document.getElementById(\'dropzone\');\n  dz.addEventListener(\'dragover\', e => { e.preventDefault(); dz.classList.add(\'drag-over\'); });\n  dz.addEventListener(\'dragleave\', () => dz.classList.remove(\'drag-over\'));\n  dz.addEventListener(\'drop\', e => {\n    e.preventDefault(); dz.classList.remove(\'drag-over\');\n    const f = e.dataTransfer.files[0];\n    if (f && f.type.startsWith(\'video/\')) {\n      selectedFile = f;\n      document.getElementById(\'file-name\').textContent = f.name;\n      document.getElementById(\'file-info\').style.display = \'block\';\n    }\n  });\n\n  /* ── Submit ─────────────────────────────────────────────── */\n  async function submitUrl() {\n    const url = document.getElementById(\'url-input\').value.trim();\n    if (!url) return;\n    clearError();\n    const fd = new FormData();\n    fd.append(\'url\', url);\n    await startJob(fd, url);\n  }\n\n  async function submitFile() {\n    if (!selectedFile) return;\n    clearError();\n    const fd = new FormData();\n    fd.append(\'file\', selectedFile);\n    await startJob(fd, selectedFile.name);\n  }\n\n  async function startJob(formData, label) {\n    try {\n      const resp = await fetch(`${API_BASE}/api/analyse`, { method: \'POST\', body: formData });\n      if (!resp.ok) throw new Error(`Server error ${resp.status}`);\n      const { job_id } = await resp.json();\n      showAnalysing(label);\n      pollJob(job_id);\n    } catch (e) {\n      showError(e.message);\n    }\n  }\n\n  /* ── Polling ────────────────────────────────────────────── */\n  let pollTimer = null;\n\n  async function pollJob(jobId) {\n    try {\n      const resp = await fetch(`${API_BASE}/api/status/${jobId}`);\n      const job = await resp.json();\n      updateAnalysingUI(job);\n\n      if (job.state === \'complete\') {\n        showVerdict(job);\n      } else if (job.state === \'error\') {\n        showError(job.error || \'Analysis failed.\');\n        showIntake();\n      } else {\n        pollTimer = setTimeout(() => pollJob(jobId), 2000);\n      }\n    } catch (e) {\n      pollTimer = setTimeout(() => pollJob(jobId), 3000);\n    }\n  }\n\n  /* ── Analysing UI updates ───────────────────────────────── */\n  function updateAnalysingUI(job) {\n    const state = job.state;\n    const analysers = job.analysers || {};\n\n    // Ingestion\n    setSigState(\'sig-ingest\',\n      [\'pending\',\'pending\'].includes(state) ? \'pending\' :\n      state === \'ingesting\' ? \'running\' : \'complete\',\n      state === \'ingesting\' ? \'Downloading…\' :\n      state === \'pending\' ? \'Waiting…\' : \'Done\'\n    );\n\n    // Metadata\n    const meta = analysers.metadata || {};\n    setSigState(\'sig-metadata\',\n      meta.status === \'complete\' ? \'complete\' :\n      meta.status === \'running\' ? \'running\' :\n      state === \'stage1\' ? \'running\' : \'pending\',\n      meta.status === \'complete\' ? \'Complete\' :\n      (meta.status === \'running\' || state === \'stage1\') ? \'Running…\' : \'Waiting…\'\n    );\n\n    // Source reputation\n    const rep = analysers.source_reputation || {};\n    setSigState(\'sig-reputation\',\n      rep.status === \'complete\' ? \'complete\' :\n      rep.status === \'skipped\'  ? \'complete\' :\n      rep.status === \'running\'  ? \'running\'  :\n      state === \'stage1\'        ? \'running\'  : \'pending\',\n      rep.status === \'complete\' ? \'Complete\' :\n      rep.status === \'skipped\'  ? \'Unavailable\' :\n      (rep.status === \'running\' || state === \'stage1\') ? \'Checking account…\' : \'Waiting…\'\n    );\n\n    // C2PA provenance\n    const cp = analysers.c2pa || {};\n    setSigState(\'sig-c2pa\',\n      cp.status === \'complete\' ? \'complete\' :\n      cp.status === \'running\'  ? \'running\'  :\n      state === \'stage1\'        ? \'running\'  : \'pending\',\n      cp.status === \'complete\' && cp.outcome === \'valid\'    ? \'Verified ✓\' :\n      cp.status === \'complete\' && cp.outcome === \'tampered\' ? \'Tampered ✗\' :\n      cp.status === \'complete\'                                 ? \'No manifest\' :\n      (cp.status === \'running\' || state === \'stage1\') ? \'Checking…\' : \'Waiting…\'\n    );\n\n    // Deepfake\n    const df = analysers.deepfake || {};\n    setSigState(\'sig-deepfake\',\n      df.status === \'complete\' || df.status === \'skipped\' ? \'complete\' :\n      df.status === \'running\' ? \'running\' :\n      state === \'stage2\' ? \'running\' : \'pending\',\n      df.status === \'complete\' ? \'Complete\' :\n      df.status === \'skipped\' ? \'Skipped (no token)\' :\n      (df.status === \'running\' || state === \'stage2\') ? \'Analysing frames…\' : \'Waiting for Stage 1…\'\n    );\n\n    // Progress bar\n    const steps = { pending: 0, ingesting: 15, stage1: 40, stage2: 75, complete: 100 };\n    document.getElementById(\'progress-fill\').style.width = (steps[state] || 0) + \'%\';\n  }\n\n  function setSigState(id, cls, label) {\n    const el = document.getElementById(id);\n    el.className = `signal-row ${cls}`;\n    el.querySelector(\'.signal-status\').textContent = label;\n  }\n\n  /* ── Views ──────────────────────────────────────────────── */\n  function showAnalysing(label) {\n    hide(\'view-intake\'); hide(\'view-verdict\'); show(\'view-analysing\');\n    document.getElementById(\'analysing-input\').textContent = label;\n    setSigState(\'sig-ingest\', \'pending\', \'Waiting…\');\n    setSigState(\'sig-metadata\', \'pending\', \'Waiting…\');\n    setSigState(\'sig-reputation\', \'pending\', \'Waiting…\');\n    setSigState(\'sig-c2pa\', \'pending\', \'Waiting…\');\n    setSigState(\'sig-deepfake\', \'pending\', \'Waiting for Stage 1…\');\n    document.getElementById(\'progress-fill\').style.width = \'0%\';\n  }\n\n  function showIntake() {\n    hide(\'view-analysing\'); hide(\'view-verdict\'); show(\'view-intake\');\n  }\n\n  function reset() {\n    if (pollTimer) clearTimeout(pollTimer);\n    showIntake();\n    document.getElementById(\'url-input\').value = \'\';\n    selectedFile = null;\n    document.getElementById(\'file-info\').style.display = \'none\';\n  }\n\n  function show(id) { document.getElementById(id).style.display = \'block\'; }\n  function hide(id) { document.getElementById(id).style.display = \'none\'; }\n\n  /* ── Verdict rendering ──────────────────────────────────── */\n  function showVerdict(job) {\n    hide(\'view-analysing\'); hide(\'view-intake\'); show(\'view-verdict\');\n    const v = job.verdict;\n\n    // Band\n    const band = document.getElementById(\'verdict-band\');\n    band.className = `verdict-band ${v.band}`;\n    const icons = { green: \'✓\', amber: \'◑\', red: \'✕\' };\n    band.querySelector(\'.verdict-indicator\').textContent = icons[v.band] || \'◑\';\n    document.getElementById(\'verdict-label\').textContent = v.label;\n    document.getElementById(\'verdict-desc\').textContent = v.description;\n\n    // Score bar\n    const pct = Math.round(v.score * 100);\n    document.getElementById(\'score-pct\').textContent = `${pct}% synthetic probability`;\n    const fill = document.getElementById(\'score-fill\');\n    fill.style.width = pct + \'%\';\n    fill.className = `score-fill ${v.band}`;\n\n    // Evidence cards\n    const cards = document.getElementById(\'evidence-cards\');\n    cards.innerHTML = \'\';\n\n    const analysers = job.analysers;\n    const defs = [\n      { key: \'metadata\',          title: \'Metadata & Container Forensics\', icon: \'🗂\' },\n      { key: \'source_reputation\', title: \'Source Reputation\',              icon: \'👤\' },\n      { key: \'c2pa\',              title: \'C2PA Provenance\',               icon: \'🔏\' },\n      { key: \'deepfake\', title: \'Frame-Level Deepfake Detection\', icon: \'🧠\' },\n    ];\n\n    const cardSection = document.createElement(\'div\');\n    cardSection.className = \'evidence-section\';\n    cardSection.innerHTML = \'<h3>Evidence</h3>\';\n\n    defs.forEach(({ key, title, icon }) => {\n      const a = analysers[key];\n      if (!a) return;\n      const scoreBand = a.score < 0.3 ? \'green\' : a.score < 0.6 ? \'amber\' : \'red\';\n      const scoreLabel = a.status === \'skipped\' ? \'Skipped\' :\n        a.status === \'error\' ? \'Error\' :\n        `${Math.round((a.score != null ? a.score : 0.5) * 100)}%`;\n\n      const card = document.createElement(\'div\');\n      card.className = \'evidence-card\';\n      card.innerHTML = `\n        <div class="evidence-card-header" onclick="toggleCard(this)">\n          <span>${icon}</span>\n          <span class="evidence-card-title">${title}</span>\n          <span class="evidence-card-score ${scoreBand}">${scoreLabel}</span>\n          <span style="color:var(--soft);font-size:12px">▾</span>\n        </div>\n        <div class="evidence-card-body">\n          <div class="evidence-summary">${a.summary || \'\'}</div>\n          ${renderSignals(a.signal_cards || a.signals || [])}\n        </div>\n      `;\n      cardSection.appendChild(card);\n    });\n\n    cards.appendChild(cardSection);\n\n    document.getElementById(\'verdict-disclaimer\').textContent = v.disclaimer;\n  }\n\n  function renderSignals(signals) {\n    if (!signals.length) return \'\';\n    const rows = signals.map(s => {\n      const flag = s.suspicious ? \' <span class="sig-flag">⚑</span>\' : \'\';\n      const val = typeof s.value === \'boolean\' ? (s.value ? \'Yes\' : \'No\') : s.value;\n      return `<tr>\n        <td class="sig-label">${s.label}${flag}</td>\n        <td class="sig-value">${val}</td>\n      </tr>`;\n    }).join(\'\');\n    return `<table class="signal-table"><tbody>${rows}</tbody></table>`;\n  }\n\n  function toggleCard(header) {\n    const body = header.nextElementSibling;\n    body.classList.toggle(\'open\');\n  }\n\n  /* ── Error handling ─────────────────────────────────────── */\n  function showError(msg) {\n    const el = document.getElementById(\'intake-error\');\n    el.textContent = `Error: ${msg}`;\n    el.style.display = \'block\';\n    showIntake();\n  }\n\n  function clearError() {\n    document.getElementById(\'intake-error\').style.display = \'none\';\n  }\n</script>\n</body>\n</html>\n'

@app.get("/", response_class=HTMLResponse)
async def serve_frontend():
    return HTMLResponse(content=FRONTEND_HTML)

@app.get("/health")
def health():
    return {"status": "ok"}

@app.post("/api/analyse")
async def analyse(
    url: str | None = Form(None),
    file: UploadFile | None = File(None),
):
    if not url and not file:
        raise HTTPException(400, "Provide either a URL or a file.")
    job_id = str(uuid.uuid4())
    workdir = tempfile.mkdtemp(prefix="skept_")
    jobs[job_id] = {
        "id": job_id,
        "state": "pending",
        "input_type": "url" if url else "file",
        "input_ref": url or file.filename,
        "workdir": workdir,
        "analysers": {},
        "verdict": None,
        "error": None,
    }
    if file:
        dest = Path(workdir) / "upload.mp4"
        async with aiofiles.open(dest, "wb") as f:
            content = await file.read()
            await f.write(content)
    asyncio.create_task(run_pipeline(job_id, url, workdir))
    return {"job_id": job_id}

@app.get("/api/status/{job_id}")
def status(job_id: str):
    job = jobs.get(job_id)
    if not job:
        raise HTTPException(404, "Job not found.")
    return {
        "id": job["id"],
        "state": job["state"],
        "input_type": job["input_type"],
        "input_ref": job["input_ref"],
        "analysers": job["analysers"],
        "verdict": job["verdict"],
        "error": job["error"],
    }

async def run_pipeline(job_id: str, url: str | None, workdir: str):
    job = jobs[job_id]
    try:
        job["state"] = "ingesting"
        video_path = await ingest(url, workdir)
        job["state"] = "stage1"
        job["analysers"]["metadata"] = {"status": "running"}
        job["analysers"]["source_reputation"] = {"status": "running"}
        job["analysers"]["c2pa"] = {"status": "running"}
        if url:
            meta_result, rep_result, c2pa_result = await asyncio.gather(
                asyncio.to_thread(run_metadata, video_path, url or ""),
                asyncio.to_thread(run_reputation, url),
                asyncio.to_thread(run_c2pa, video_path),
            )
        else:
            meta_result, c2pa_result = await asyncio.gather(
                asyncio.to_thread(run_metadata, video_path, ""),
                asyncio.to_thread(run_c2pa, video_path),
            )
            rep_result = {
                "analyser": "source_reputation", "status": "skipped",
                "skip_reason": "file_upload_no_url", "score": 0.5,
                "signal_cards": [], "summary": "Source reputation requires a URL.",
            }
        job["analysers"]["metadata"] = meta_result
        job["analysers"]["source_reputation"] = rep_result
        job["analysers"]["c2pa"] = c2pa_result
        job["state"] = "stage2"
        job["analysers"]["deepfake"] = {"status": "running"}
        deepfake_result = await run_deepfake(video_path)
        job["analysers"]["deepfake"] = deepfake_result
        verdict = fuse(meta_result, rep_result, c2pa_result, deepfake_result)
        job["verdict"] = verdict
        job["state"] = "complete"
    except Exception as e:
        job["state"] = "error"
        job["error"] = str(e)

async def ingest(url: str | None, workdir: str) -> str:
    if url:
        out = Path(workdir) / "video.mp4"
        proc = await asyncio.create_subprocess_exec(
            "yt-dlp", url,
            "-o", str(out),
            "-f", "bestvideo[ext=mp4]+bestaudio[ext=m4a]/best[ext=mp4]/best",
            "--merge-output-format", "mp4",
            "--no-playlist", "--quiet",
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
        )
        _, stderr = await proc.communicate()
        if proc.returncode != 0:
            raise RuntimeError(f"yt-dlp failed: {stderr.decode()}")
        if not out.exists():
            candidates = list(Path(workdir).glob("video.*"))
            if not candidates:
                raise RuntimeError("yt-dlp produced no output file.")
            out = candidates[0]
        return str(out)
    else:
        candidates = list(Path(workdir).glob("upload.*"))
        if not candidates:
            raise RuntimeError("No uploaded file found.")
        return str(candidates[0])
